+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track = {min: number; fr: number; auto: boolean};
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const tokenize = (template: string): string[] =>
+	template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {min: 0, fr: 0, auto: true};
+	const minmax = /^minmax\\(\\s*(\\d+)\\s*,\\s*(\\d+(?:\\.\\d+)?fr|\\d+)\\s*\\)$/.exec(value);
+	if (minmax) {
+		const max = minmax[2]!;
+		return {min: Number(minmax[1]), fr: max.endsWith('fr') ? Number.parseFloat(max) : 0, auto: false};
+	}
+	if (value.endsWith('fr')) return {min: 0, fr: Number.parseFloat(value)};
+	return {min: Number(value), fr: 0, auto: false};
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	template ? tokenize(template).map(parseTrack).filter(track => Number.isFinite(track.min) && Number.isFinite(track.fr)) : [];
+
+const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') return [value - 1, value];
+	if (!value) return;
+	const values = value.split('/').map(part => Number.parseInt(part.trim(), 10));
+	if (values.some(value => !Number.isInteger(value) || value < 1)) return;
+	return values.length === 1 ? [values[0]! - 1, values[0]!] : [values[0]! - 1, values[1]! - 1];
+};
+
+const resolveTracks = (tracks: Track[], available: number, intrinsic: number[], gap: number): number[] => {
+	const minimum = tracks.reduce((sum, track, index) => sum + track.min + (track.auto ? intrinsic[index]! : 0), 0);
+	const totalFr = tracks.reduce((sum, track) => sum + track.fr, 0);
+	const remaining = Math.max(0, available - minimum - Math.max(0, tracks.length - 1) * gap);
+	return tracks.map((track, index) => track.min + (track.auto ? intrinsic[index]! : 0) + (track.fr ? remaining * track.fr / totalFr : 0));
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	if (!node.yogaNode || node.style.display !== 'grid') return;
+	const children = node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) return;
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const placements: Placement[] = [];
+	let cursorColumn = 0;
+	let cursorRow = 0;
+	for (const child of children) {
+		const specifiedColumn = parsePlacement(child.style.gridColumn);
+		const specifiedRow = parsePlacement(child.style.gridRow);
+		const column = specifiedColumn?.[0] ?? cursorColumn;
+		const columnEnd = specifiedColumn?.[1] ?? column + 1;
+		const row = specifiedRow?.[0] ?? cursorRow;
+		const rowEnd = specifiedRow?.[1] ?? row + 1;
+		placements.push({column, columnEnd, row, rowEnd});
+		cursorColumn = columnEnd;
+		if (cursorColumn >= columns.length) { cursorColumn = 0; cursorRow++; }
+	}
+	const rows = parseTracks(node.style.gridTemplateRows);
+	const rowCount = Math.max(rows.length, ...placements.map(placement => placement.rowEnd), 0);
+	while (rows.length < rowCount) rows.push({min: 0, fr: 0, auto: true});
+	const intrinsicColumns = Array.from({length: columns.length}, () => 0);
+	const intrinsicRows = Array.from({length: rows.length}, () => 0);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index]!;
+		if (placement.columnEnd - placement.column === 1) intrinsicColumns[placement.column] = Math.max(intrinsicColumns[placement.column]!, child.yogaNode!.getComputedWidth());
+		if (placement.rowEnd - placement.row === 1) intrinsicRows[placement.row] = Math.max(intrinsicRows[placement.row]!, child.yogaNode!.getComputedHeight());
+	}
+	const yoga = node.yogaNode;
+	const leftInset = yoga.getComputedPadding(Yoga.EDGE_LEFT) + yoga.getComputedBorder(Yoga.EDGE_LEFT);
+	const topInset = yoga.getComputedPadding(Yoga.EDGE_TOP) + yoga.getComputedBorder(Yoga.EDGE_TOP);
+	const width = yoga.getComputedWidth() - leftInset - yoga.getComputedPadding(Yoga.EDGE_RIGHT) - yoga.getComputedBorder(Yoga.EDGE_RIGHT);
+	const height = yoga.getComputedHeight() - topInset - yoga.getComputedPadding(Yoga.EDGE_BOTTOM) - yoga.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const columnSizes = resolveTracks(columns, width, intrinsicColumns, columnGap);
+	const rowSizes = resolveTracks(rows, height, intrinsicRows, rowGap);
+	const columnOffsets = offsets(columnSizes, columnGap);
+	const rowOffsets = offsets(rowSizes, rowGap);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index]!;
+		const childYoga = child.yogaNode!;
+		childYoga.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		childYoga.setPosition(Yoga.EDGE_LEFT, leftInset + columnOffsets[placement.column]!);
+		childYoga.setPosition(Yoga.EDGE_TOP, topInset + rowOffsets[placement.row]!);
+		childYoga.setWidth(columnOffsets[placement.columnEnd - 1]! + columnSizes[placement.columnEnd - 1]! - columnOffsets[placement.column]!);
+		childYoga.setHeight(rowOffsets[placement.rowEnd - 1]! + rowSizes[placement.rowEnd - 1]! - rowOffsets[placement.row]!);
+	}
+	if (node.style.height === undefined) yoga.setHeight(topInset + rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rows.length - 1) * rowGap + yoga.getComputedPadding(Yoga.EDGE_BOTTOM) + yoga.getComputedBorder(Yoga.EDGE_BOTTOM));
+};
+
+export const layoutGrids = (root: DOMElement): void => {
+	const visit = (node: DOMElement): void => {
+		for (const child of node.childNodes) if (child.nodeName !== '#text') visit(child);
+		layoutGrid(node);
+	};
+	visit(root);
+};
