type Track = {min: number; fr: number; auto: boolean};
type Placement = {
	column: number;
	columnEnd: number;
	row: number;
	rowEnd: number;
};

const tokenize = (template: string): string[] =>
	template.match(/minmax\([^)]*\)|\S+/g) ?? [];

const parseTrack = (value: string): Track => {
	if (value === 'auto') return {min: 0, fr: 0, auto: true};
	const minmax = /^minmax\(\s*(\d+)\s*,\s*(\d+(?:\.\d+)?fr|\d+)\s*\)$/.exec(
		value,
	);
	if (minmax) {
		const max = minmax[2]!;
		return {
			min: Number(minmax[1]),
			fr: max.endsWith('fr') ? Number.parseFloat(max) : 0,
			auto: false,
		};
	}
	if (value.endsWith('fr'))
		return {min: 0, fr: Number.parseFloat(value), auto: false};
	return {min: Number(value), fr: 0, auto: false};
};

const parseTracks = (template: string | undefined): Track[] =>
	template
		? tokenize(template)
				.map(parseTrack)
